// Data source: static JSON generated by scripts/build_site_data.py
// Cache-busting: append build timestamp so browsers fetch fresh data after deploy
const CACHE_BUST = `v=${Date.now()}`;
const DATA_URL = `static/data/papers.json?${CACHE_BUST}`;
const LEADERBOARD_URL = `static/data/leaderboard.json?${CACHE_BUST}`;

let allPapers = [];    // raw experiment entries
let groupedPapers = []; // grouped by DOI

// Default models shown (max 3 at a time)
const DEFAULT_VISIBLE_MODELS = ['claude-sonnet-4-6', 'gemini-2.5-flash', 'gpt-4o'];
const MAX_VISIBLE_MODELS = 3;
let visibleModels = [...DEFAULT_VISIBLE_MODELS];

// Model color palette — add new models here
const MODEL_COLORS = {
  'gpt-4o':              { fill: '#3b82f6', fillAlpha: 0.35, stroke: '#3b82f6', label: 'GPT-4o' },
  'claude-sonnet-4-6': { fill: '#8b5cf6', fillAlpha: 0.35, stroke: '#8b5cf6', label: 'Claude Sonnet 4.6' },
  'claude-haiku-4-5-20251001': { fill: '#f59e0b', fillAlpha: 0.35, stroke: '#f59e0b', label: 'Claude Haiku 4.5' },
  'claude-opus-4-6':    { fill: '#06b6d4', fillAlpha: 0.35, stroke: '#06b6d4', label: 'Claude Opus 4.6' },
  'gemini-2.5-pro':      { fill: '#10b981', fillAlpha: 0.35, stroke: '#10b981', label: 'Gemini 2.5 Pro' },
  'gemini-2.5-flash':    { fill: '#34d399', fillAlpha: 0.35, stroke: '#34d399', label: 'Gemini 2.5 Flash' },
};
const DEFAULT_COLORS = [
  { fill: '#f97316', fillAlpha: 0.35, stroke: '#f97316' },
  { fill: '#14b8a6', fillAlpha: 0.35, stroke: '#14b8a6' },
  { fill: '#ec4899', fillAlpha: 0.35, stroke: '#ec4899' },
];
function getModelColor(modelName) {
  if (MODEL_COLORS[modelName]) return MODEL_COLORS[modelName];
  const idx = Object.keys(MODEL_COLORS).length % DEFAULT_COLORS.length;
  return { ...DEFAULT_COLORS[idx], label: modelName };
}

// ---------------------------------------------------------------------------
// Init
// ---------------------------------------------------------------------------
document.addEventListener('DOMContentLoaded', async () => {
  const [papersRes, lbRes] = await Promise.all([
    fetch(DATA_URL),
    fetch(LEADERBOARD_URL).catch(() => null),
  ]);
  allPapers = await papersRes.json();
  groupedPapers = groupByDoi(allPapers);

  if (lbRes && lbRes.ok) {
    const leaderboard = await lbRes.json();
    renderLeaderboard(leaderboard);
  }

  renderPaperList(groupedPapers);

  document.getElementById('searchInput').addEventListener('input', filterPapers);
  document.getElementById('journalFilter').addEventListener('change', filterPapers);

  // Close dropdowns when clicking outside
  document.addEventListener('click', (e) => {
    document.querySelectorAll('.model-selector.open').forEach(sel => {
      if (!sel.contains(e.target)) sel.classList.remove('open');
    });
    // Close info tooltips
    document.querySelectorAll('.info-tooltip:not(.hidden)').forEach(tip => {
      if (!tip.previousElementSibling?.contains(e.target) && !tip.contains(e.target)) {
        tip.classList.add('hidden');
      }
    });
  });
});

// ---------------------------------------------------------------------------
// Group experiments by DOI into papers
// ---------------------------------------------------------------------------
function groupByDoi(papers) {
  const map = {};
  papers.forEach(p => {
    if (!map[p.doi]) {
      const baseTitle = p.title.replace(/ \u2014 .*$/, '');
      map[p.doi] = {
        doi: p.doi,
        title: baseTitle,
        authors: p.authors,
        journal: p.journal,
        year: p.year,
        replication_url: p.replication_url,
        experiments: [],
      };
    }
    map[p.doi].experiments.push(p);
  });
  return Object.values(map);
}

// ---------------------------------------------------------------------------
// Filtering
// ---------------------------------------------------------------------------
function filterPapers() {
  const query = document.getElementById('searchInput').value.toLowerCase();
  const journal = document.getElementById('journalFilter').value;

  let papers = groupedPapers;
  if (journal) papers = papers.filter(p => p.journal === journal);
  if (query) {
    papers = papers.filter(p =>
      p.title.toLowerCase().includes(query) ||
      p.authors.join(' ').toLowerCase().includes(query) ||
      p.experiments.some(e => (e.description || '').toLowerCase().includes(query))
    );
  }
  renderPaperList(papers);
}

// ---------------------------------------------------------------------------
// Model leaderboard
// ---------------------------------------------------------------------------
function renderLeaderboard(leaderboard) {
  const container = document.getElementById('leaderboard');
  if (!container) return;

  // Support both old flat array and new {text: [...], visual: [...]} format
  let sections;
  if (Array.isArray(leaderboard)) {
    sections = { text: leaderboard };
  } else {
    sections = leaderboard;
  }

  const MODALITY_LABELS = { text: 'Text-Based Experiments', visual: 'Visual Experiments' };
  const modalities = Object.keys(sections).filter(k => sections[k] && sections[k].length > 0);
  if (modalities.length === 0) return;

  const showHeaders = modalities.length > 1;

  const tablesHtml = modalities.map(modality => {
    const entries = sections[modality];
    const header = showHeaders
      ? `<h3 style="font-size:1rem;font-weight:600;margin:1.2rem 0 0.5rem">${MODALITY_LABELS[modality] || modality}</h3>`
      : '';

    const rows = entries.map((entry, i) => {
      const mc = getModelColor(entry.model);
      const rank = i + 1;
      const fid = entry.mean_fidelity != null ? entry.mean_fidelity.toFixed(3) : '\u2014';
      const w = entry.mean_wasserstein != null ? entry.mean_wasserstein.toFixed(2) : '\u2014';
      const nonsig = entry.nonsig_rate != null ? (entry.nonsig_rate * 100).toFixed(0) + '%' : '\u2014';

      return `
        <tr>
          <td class="num" style="font-weight:700">${rank}</td>
          <td style="font-weight:600;color:${mc.stroke}">${mc.label || entry.model}</td>
          <td class="num" style="font-weight:600">${fid}</td>
          <td class="num">${w}</td>
          <td class="num">${nonsig}</td>
          <td class="num">${entry.n_papers}</td>
        </tr>
      `;
    }).join('');

    return `
      ${header}
      <table class="results-table leaderboard-table">
        <thead>
          <tr>
            <th class="num">Rank</th>
            <th>Model</th>
            <th class="num">Fidelity</th>
            <th class="num">Mean W\u2081</th>
            <th class="num">Non-sig Rate</th>
            <th class="num">Papers</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>
    `;
  }).join('');

  container.innerHTML = `
    ${tablesHtml}
    <p style="font-size:0.78rem;color:#888;margin-top:0.5rem">
      Ranked by Fidelity Score F = 1 \u2212 EMD(sim,real)/EMD(random,real). F=1 is perfect replication, F=0 is no better than random.
      W\u2081 = Wasserstein-1 distance (lower = better). Non-sig Rate = fraction of conditions where replicated mean is not significantly different from original.
      All means are paper-weighted: first averaged within each paper, then across papers (each paper counts equally).
    </p>
  `;
}

// ---------------------------------------------------------------------------
// Paper list (one card per paper)
// ---------------------------------------------------------------------------
function renderPaperList(papers) {
  const container = document.getElementById('paper-list');
  document.getElementById('paper-detail').classList.add('hidden');
  document.getElementById('leaderboard-section').classList.remove('hidden');
  container.classList.remove('hidden');

  if (!papers.length) {
    container.innerHTML = '<p style="color:#888">No papers found.</p>';
    return;
  }

  container.innerHTML = papers.map(p => {
    const numExp = p.experiments.length;
    const numReplicated = p.experiments.filter(e => e.has_results).length;
    const allReplicated = numReplicated === numExp;
    const noneReplicated = numReplicated === 0;

    return `
      <div class="paper-card" onclick="showPaperByDoi('${p.doi}')">
        <div class="title">${p.title}</div>
        <div class="meta">
          <span class="journal">${p.journal}</span>
          ${p.authors.join(', ')} (${p.year})
          &middot; <a href="https://doi.org/${p.doi}" target="_blank" onclick="event.stopPropagation()">DOI</a>
          &middot; ${numExp} experiment${numExp > 1 ? 's' : ''}
        </div>
        <div class="description">${p.experiments[0].description}</div>
        <span class="status ${allReplicated ? 'replicated' : (noneReplicated ? 'pending' : 'partial')}">
          ${allReplicated ? 'Replicated' : (noneReplicated ? 'Pending' : `${numReplicated}/${numExp} Replicated`)}
        </span>
      </div>
    `;
  }).join('');
}

// ---------------------------------------------------------------------------
// Paper detail (grouped by DOI, shows experiments)
// ---------------------------------------------------------------------------
function showPaperByDoi(doi) {
  try {
    const group = groupedPapers.find(p => p.doi === doi);
    if (!group) return;

    document.getElementById('paper-list').classList.add('hidden');
    document.getElementById('leaderboard-section').classList.add('hidden');
    const detail = document.getElementById('paper-detail');
    detail.classList.remove('hidden');

    const experiments = group.experiments;

    detail.innerHTML = `
      <span class="back-link" onclick="goBack()">&larr; Back to papers</span>

      <div class="detail-header">
        <h2>${group.title}</h2>
        <div class="meta">
          <span class="journal" style="display:inline-block;background:#eef2ff;color:#3730a3;padding:0.1rem 0.45rem;border-radius:4px;font-weight:600;font-size:0.8rem;margin-right:0.4rem">${group.journal}</span>
          ${group.authors.join(', ')} (${group.year})
          &middot; <a href="https://doi.org/${group.doi}" target="_blank">DOI</a>
          ${group.replication_url ? `&middot; <a href="${group.replication_url}" target="_blank">Replication data</a>` : ''}
          ${(() => {
            const repro = [];
            group.experiments.forEach(exp => {
              if (exp.has_reproduce_text) repro.push({ id: exp.id, modality: 'text' });
              if (exp.has_reproduce_visual) repro.push({ id: exp.id, modality: 'visual' });
            });
            return repro.map(r =>
              `&middot; <a href="#" class="repro-link" onclick="event.preventDefault();showReproduction('${r.id}','${r.modality}')">Reproduce (${r.modality})</a>`
            ).join('\n            ');
          })()}
        </div>
      </div>

      ${experiments.length > 1 ? `
      <div class="experiment-list">
        <div class="experiment-list-label">Experiments</div>
        ${experiments.map((exp, i) => {
          const expLabel = exp.title.includes('\u2014') ? exp.title.split('\u2014').pop().trim() : exp.title;
          return `
          <div class="experiment-card ${i === 0 ? 'active' : ''}" onclick="showExperiment('${exp.id}', this)">
            <div class="experiment-card-number">Experiment ${i + 1}</div>
            <div class="experiment-card-title">${expLabel}</div>
            <span class="status ${exp.has_results ? 'replicated' : 'pending'}">
              ${exp.has_results ? 'Replicated' : 'Pending'}
            </span>
          </div>
        `}).join('')}
      </div>
      ` : ''}

      <div id="experiment-detail">
        ${renderExperiment(experiments[0])}
      </div>
    `;

    window._experiments = experiments;
  } catch (e) {
    console.error('Error rendering paper:', e);
    document.getElementById('paper-detail').innerHTML = `
      <span class="back-link" onclick="goBack()">&larr; Back to papers</span>
      <p style="color:red;margin-top:2rem">Error loading paper: ${e.message}</p>
    `;
  }
}

function showExperiment(expId, el) {
  const exp = window._experiments.find(e => e.id === expId);
  if (!exp) return;
  document.querySelectorAll('.experiment-card').forEach(c => c.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('experiment-detail').innerHTML = renderExperiment(exp);
}

function renderExperiment(paper, resetModels = true) {
  window._currentExperiment = paper;
  const hasComps = paper.comparisons && paper.comparisons.length > 0;
  window._comparisons = paper.comparisons || [];

  // Reset to default models when entering a new paper/experiment.
  // Skip reset when re-rendering after a model toggle (resetModels=false).
  if (resetModels && hasComps) {
    const availableKeys = paper.comparisons.map(c => compKey(c));
    // Match defaults by model name prefix (so "gpt-4o" matches "gpt-4o" and "gpt-4o_visual")
    visibleModels = DEFAULT_VISIBLE_MODELS
      .flatMap(m => availableKeys.filter(k => k === m || k.startsWith(m + '_')))
      .slice(0, MAX_VISIBLE_MODELS);
    if (visibleModels.length === 0) visibleModels = availableKeys.slice(0, MAX_VISIBLE_MODELS);
  }

  const filteredComps = getVisibleComparisons(paper.comparisons);
  const hasFiltered = filteredComps.length > 0;

  try {
    return `
      <div class="detail-section">
        <div class="section-header">
          <h3>Experiment Design</h3>
          <button class="info-btn" onclick="this.nextElementSibling.classList.toggle('hidden')" title="What do these fields mean?">i</button>
          <div class="info-tooltip hidden">
            ${renderDesignTooltip()}
          </div>
        </div>
        <p>${paper.description || ''}</p>
        ${renderDesignSummary(paper.design_summary, paper.original_results)}
      </div>

      <div class="detail-section">
        <h3>Original Results</h3>
        ${renderOriginalResults(paper.original_results)}
      </div>

      ${hasComps ? `
        <div class="detail-section">
          <div class="section-header">
            <h3>Simulation Results</h3>
            ${renderModelSelector(paper.comparisons)}
          </div>
          ${hasFiltered ? renderAllModels(filteredComps, paper) : '<p style="color:#888">Select at least one model above.</p>'}
        </div>
        ${renderPaperTests(filteredComps)}
      ` : `
        <div class="detail-section">
          <h3>Simulation Results</h3>
          <p style="color:#888">No replication results yet.</p>
        </div>
      `}
      ${renderNotes(paper.notes)}
    `;
  } catch (e) {
    console.error('Error in renderExperiment:', e);
    return `<p style="color:red">Error rendering experiment: ${e.message}</p>`;
  }
}

function goBack() {
  document.getElementById('paper-detail').classList.add('hidden');
  document.getElementById('paper-list').classList.remove('hidden');
  document.getElementById('leaderboard-section').classList.remove('hidden');
}

// ---------------------------------------------------------------------------
// Model selector dropdown (checkbox-based, max 3)
// ---------------------------------------------------------------------------
function renderModelSelector(comparisons) {
  if (!comparisons || comparisons.length <= 1) return '';

  // Show modality suffix when a model appears in multiple modalities
  const hasMultiModality = comparisons.some((c, i) =>
    comparisons.some((c2, j) => i !== j && c2.model === c.model && c2.modality !== c.modality)
  );

  const items = comparisons.map(c => {
    const mc = getModelColor(c.model);
    const key = compKey(c);
    const label = hasMultiModality
      ? `${mc.label || c.model} (${c.modality || 'text'})`
      : (mc.label || c.model);
    const checked = visibleModels.includes(key) ? 'checked' : '';
    const disabled = !visibleModels.includes(key) && visibleModels.length >= MAX_VISIBLE_MODELS ? 'disabled' : '';
    return `<label class="model-selector-item ${disabled ? 'disabled' : ''}">
      <input type="checkbox" value="${key}" ${checked} ${disabled}
             onchange="toggleModelVisibility('${key}', this.checked)"/>
      <span class="model-selector-swatch" style="background:${mc.stroke}"></span>
      ${label}
    </label>`;
  }).join('');

  return `
    <div class="model-selector">
      <button class="model-selector-btn" onclick="this.parentElement.classList.toggle('open')">
        Models (${visibleModels.length}/${MAX_VISIBLE_MODELS}) &#9662;
      </button>
      <div class="model-selector-dropdown">${items}</div>
    </div>
  `;
}

function toggleModelVisibility(model, checked) {
  if (checked && !visibleModels.includes(model)) {
    if (visibleModels.length >= MAX_VISIBLE_MODELS) return;
    visibleModels.push(model);
  } else if (!checked) {
    visibleModels = visibleModels.filter(m => m !== model);
  }
  refreshExperimentView();
}

function refreshExperimentView() {
  const exp = window._currentExperiment;
  if (!exp) return;
  // Preserve dropdown open state across re-render
  const wasOpen = document.querySelector('.model-selector.open') != null;
  // Pass resetModels=false so model toggle isn't undone by re-render
  document.getElementById('experiment-detail').innerHTML = renderExperiment(exp, false);
  if (wasOpen) {
    const sel = document.querySelector('.model-selector');
    if (sel) sel.classList.add('open');
  }
}

/** Unique key for a comparison entry: model name + modality suffix when non-text. */
function compKey(comp) {
  return comp.modality && comp.modality !== 'text'
    ? `${comp.model}_${comp.modality}`
    : comp.model;
}

function getVisibleComparisons(comparisons) {
  if (!comparisons) return [];
  return comparisons.filter(c => visibleModels.includes(compKey(c)));
}

// ---------------------------------------------------------------------------
// Original results
// ---------------------------------------------------------------------------
function renderOriginalResults(results) {
  if (!results) return '<p style="color:#888">No original results available.</p>';

  const rows = Object.entries(results).map(([condition, stats]) => `
    <tr>
      <td>${formatCondition(condition)}</td>
      <td class="num">${stats.mean != null ? stats.mean.toFixed(4) : '\u2014'}</td>
      <td class="num">${stats.se != null ? stats.se.toFixed(4) : '\u2014'}</td>
      <td class="num">${stats.n ?? '\u2014'}</td>
    </tr>
  `).join('');

  return `
    <table class="results-table">
      <thead>
        <tr><th>Condition</th><th class="num">Mean</th><th class="num">SE</th><th class="num">N</th></tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

// ---------------------------------------------------------------------------
// Design summary table
// ---------------------------------------------------------------------------
// ---------------------------------------------------------------------------
// Design field definitions — single source of truth for the table AND tooltip.
// Each entry: { key, label, description }
// When adding/removing/renaming a field, update THIS array and both the table
// and tooltip will stay in sync automatically.
// ---------------------------------------------------------------------------
const DESIGN_FIELDS = [
  { key: 'decision_type',    label: 'Decision Type',    description: 'The general category of decision participants make (e.g., Binary Choice, Willingness to Pay, Numerical Estimation).' },
  { key: 'outcome_variable', label: 'Outcome Variable', description: 'The measured variable used to compare original and simulated results. If multiple exist, the primary one is marked.' },
  { key: 'scale',            label: 'Scale',            description: 'The range or set of options available to participants when making their decision.' },
  { key: 'conditions',       label: 'Conditions',       description: 'The experimental treatment arms. N shows the number of observations per condition in the original study.' },
  { key: 'sample',           label: 'Sample',           description: 'Total number of unique subjects in the original experiment and the type of participant pool.' },
  { key: 'observations',     label: 'Observations',     description: 'Total data points across all conditions. May differ from sample size: in within-subject designs each subject contributes multiple observations, while in between-subject designs it equals the number of subjects.' },
];

function renderDesignTooltip() {
  return DESIGN_FIELDS.map(f =>
    `<strong>${f.label}</strong> — ${f.description}`
  ).join('<br>');
}

function renderDesignSummary(ds, originalResults) {
  if (!ds) return '';

  // Outcome variables
  const outcomeRows = (ds.outcome_variables || []).map((ov, i) => {
    const isPrimary = i === 0 && ds.outcome_variables.length > 1;
    return `<span class="design-tag">${ov.name}${isPrimary ? ' (primary)' : ''}</span>`;
  }).join(' ');

  // Conditions with per-condition N
  const condRows = (ds.conditions || []).map(c => {
    const n = originalResults?.[c]?.n;
    return `<span class="design-tag">${formatCondition(c)}${n != null ? ` (N=${n})` : ''}</span>`;
  }).join(' ');

  // Build rows using the same labels from DESIGN_FIELDS
  const fieldLabel = key => DESIGN_FIELDS.find(f => f.key === key)?.label ?? key;
  const rows = [
    { label: fieldLabel('decision_type'), value: ds.decision_type },
    { label: fieldLabel('outcome_variable'), value: outcomeRows, html: true },
    { label: fieldLabel('scale'), value: ds.outcome_variables?.[0]?.scale },
    { label: fieldLabel('conditions'), value: condRows, html: true },
    { label: fieldLabel('sample'), value: `${ds.sample_size ?? '—'} subjects (${ds.sample_type || '—'})` },
    { label: fieldLabel('observations'), value: ds.total_observations ?? '—' },
  ].filter(r => r.value);

  const tableRows = rows.map(r => `
    <tr>
      <td class="design-label">${r.label}</td>
      <td>${r.html ? r.value : escapeHtml(String(r.value))}</td>
    </tr>
  `).join('');

  return `
    <table class="design-table">
      <tbody>${tableRows}</tbody>
    </table>
  `;
}

function escapeHtml(str) {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// ---------------------------------------------------------------------------
// All-models combined view
// ---------------------------------------------------------------------------
function renderAllModels(comparisons, paper) {
  if (!comparisons || comparisons.length === 0 || !comparisons[0].conditions) {
    return '<p style="color:#888">No comparison data available.</p>';
  }
  const conditionNames = comparisons[0].conditions.map(c => c.condition);

  // Combined legend
  const legendItems = comparisons.map(comp => {
    const mc = getModelColor(comp.model);
    return `<span style="display:inline-flex;align-items:center;margin-right:1rem;font-size:0.82rem">
      <span style="display:inline-block;width:12px;height:12px;background:${mc.fill};border-radius:2px;margin-right:4px;opacity:0.7"></span>
      ${mc.label || comp.model}
    </span>`;
  }).join('');

  const legend = `
    <div class="chart-legend">
      <span style="display:inline-flex;align-items:center;margin-right:1rem;font-size:0.82rem">
        <span style="display:inline-block;width:12px;height:12px;background:#dc2626;border-radius:2px;margin-right:4px;opacity:0.7"></span>
        Original
      </span>
      ${legendItems}
    </div>
  `;

  // Combined bar chart
  const allVals = comparisons.flatMap(comp =>
    comp.conditions.map(c => Math.abs(parseFloat(c.original_mean || 0)))
  ).concat(comparisons.flatMap(comp =>
    comp.conditions.map(c => Math.abs(parseFloat(c.replicated_mean || 0)))
  ));
  const maxVal = Math.max(...allVals) * 1.2 || 1;

  const barGroups = conditionNames.map(cond => {
    const origMean = parseFloat(comparisons[0].conditions.find(c => c.condition === cond)?.original_mean || 0);
    const origH = (Math.abs(origMean) / maxVal) * 140;

    const modelBars = comparisons.map(comp => {
      const mc = getModelColor(comp.model);
      const condData = comp.conditions.find(c => c.condition === cond);
      const repMean = parseFloat(condData?.replicated_mean || 0);
      const repH = (Math.abs(repMean) / maxVal) * 140;
      return `<div class="bar" style="height:${repH}px;background:${mc.fill};opacity:0.7">
        <span class="bar-value">${fmtNum(repMean)}</span>
      </div>`;
    }).join('');

    return `
      <div class="bar-group">
        <div class="bar-pair">
          <div class="bar original" style="height:${origH}px">
            <span class="bar-value">${fmtNum(origMean)}</span>
          </div>
          ${modelBars}
        </div>
        <div class="bar-label">${formatCondition(cond)}</div>
      </div>
    `;
  }).join('');

  const chart = `${legend}<div class="bar-chart">${barGroups}</div>`;

  // Per-model tables with tabs
  const hasMultiMod = comparisons.some((c, i) =>
    comparisons.some((c2, j) => i !== j && c2.model === c.model && c2.modality !== c.modality)
  );
  const tabs = comparisons.length > 1 ? `
    <div class="model-tabs">
      ${comparisons.map((c, i) => {
        const mc = getModelColor(c.model);
        const tabLabel = hasMultiMod
          ? `${mc.label || c.model} (${c.modality || 'text'})`
          : (mc.label || c.model);
        return `<button class="model-tab ${i === 0 ? 'active' : ''}"
                style="border-bottom-color:${i === 0 ? mc.stroke : 'transparent'}"
                onclick="switchModel(${i})">${tabLabel}</button>`;
      }).join('')}
    </div>
  ` : '';

  const tableContent = renderComparisonTable(comparisons[0]);

  // Distribution plots (all models overlaid)
  const xAxisLabel = paper?.design_summary?.outcome_variables?.[0]?.name || '';
  const distPlots = renderAllModelDistributions(comparisons, conditionNames, xAxisLabel);

  const meansHeader = `<h4 style="font-size:0.95rem;font-weight:600;margin-top:1.5rem;margin-bottom:0.75rem">Statistical Comparison</h4>`;

  return distPlots + meansHeader + chart + tabs +
    `<div id="comparison-content">${tableContent}</div>`;
}

function switchModel(idx) {
  const filtered = getVisibleComparisons(window._comparisons);
  document.querySelectorAll('.model-tab').forEach((tab, i) => {
    const mc = getModelColor(filtered[i].model);
    tab.classList.toggle('active', i === idx);
    tab.style.borderBottomColor = i === idx ? mc.stroke : 'transparent';
  });
  document.getElementById('comparison-content').innerHTML =
    renderComparisonTable(filtered[idx]);
}

function renderComparisonTable(comp) {
  const conditions = comp.conditions;
  const modelName = comp.model;
  const mc = getModelColor(modelName);

  const rows = conditions.map(c => {
    const pval = parseFloat(c.p_value);
    const isSig = pval < 0.05;
    const hasW = c.wasserstein != null;
    const hasF = c.fidelity != null;
    return `
      <tr>
        <td>${formatCondition(c.condition)}</td>
        <td class="num">${fmtNum(c.original_mean)}</td>
        <td class="num">${fmtNum(c.replicated_mean)}</td>
        <td class="num ${isSig ? 'sig' : 'ns'}">${fmtNum(c.p_value)}${isSig ? ' *' : ''}</td>
        <td class="num">${hasW ? fmtNum(c.wasserstein) : '\u2014'}</td>
        <td class="num">${hasF ? fmtNum(c.fidelity) : '\u2014'}</td>
      </tr>
    `;
  }).join('');

  return `
    <p style="font-size:0.85rem;color:#555;margin-bottom:0.5rem">
      Model: <strong style="color:${mc.stroke}">${mc.label || modelName}</strong>
    </p>
    <table class="results-table">
      <thead>
        <tr>
          <th>Condition</th>
          <th class="num">Original Mean</th>
          <th class="num">Replicated Mean</th>
          <th class="num">p-value</th>
          <th class="num">W\u2081 Distance</th>
          <th class="num">Fidelity</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
    <p style="font-size:0.78rem;color:#888;margin-top:0.5rem">
      * p &lt; 0.05 indicates the replicated mean differs significantly from the original.
      Non-significant = closer replication.
      W\u2081 = Wasserstein-1 distance (lower = closer distributions).
      Fidelity F = 1 &minus; EMD(sim,real)/EMD(random,real); 1 = perfect, 0 = random, &lt;0 = worse than random.
    </p>
  `;
}

// ---------------------------------------------------------------------------
// Paper notes (data issues, extraction decisions, etc.)
// ---------------------------------------------------------------------------
function renderNotes(notes) {
  if (!notes || notes.length === 0) return '';

  const categoryLabels = {
    data: 'Data Issue',
    design: 'Design Note',
    extraction: 'Extraction',
    validation: 'Validation',
  };

  const items = notes.map(n => {
    const label = categoryLabels[n.category] || n.category;
    return `<li><span class="note-category">${label}</span> ${n.message}</li>`;
  }).join('');

  return `
    <details class="notes-section">
      <summary>Notes (${notes.length})</summary>
      <ul class="notes-list">${items}</ul>
    </details>
  `;
}

// ---------------------------------------------------------------------------
// Paper-level statistical tests
// ---------------------------------------------------------------------------
function renderPaperTests(comparisons) {
  const hasTests = comparisons.some(c => c.paper_tests && c.paper_tests.length > 0);
  if (!hasTests) return '';

  const rows = [];
  comparisons.forEach(comp => {
    if (!comp.paper_tests || comp.paper_tests.length === 0) return;
    const mc = getModelColor(comp.model);
    comp.paper_tests.forEach(pt => {
      const conclusion = pt.conclusion || '';
      const conclusionClass = conclusion.includes('correct_significant') ? 'correct-sig'
        : conclusion.includes('correct_direction') ? 'correct-dir'
        : conclusion.includes('wrong') ? 'wrong'
        : 'null';
      const conclusionLabel = conclusion.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
      rows.push(`
        <tr>
          <td style="color:${mc.stroke};font-weight:600">${mc.label || comp.model}</td>
          <td>${pt.test_name || ''}</td>
          <td class="num">${fmtNum(pt.original_effect)}</td>
          <td class="num">${fmtNum(pt.effect)}</td>
          <td class="num">${fmtNum(pt.p_value)}</td>
          <td class="conclusion ${conclusionClass}">${conclusionLabel}</td>
        </tr>
      `);
    });
  });

  return `
    <div class="detail-section" style="border-left:3px solid #2563eb">
      <h3>Paper-Level Statistical Tests</h3>
      <p style="font-size:0.78rem;color:#888;margin-bottom:0.5rem">
        Same tests as reported in the original paper, applied to simulated data.
      </p>
      <table class="results-table">
        <thead>
          <tr>
            <th>Model</th>
            <th>Test</th>
            <th class="num">Original Effect</th>
            <th class="num">Simulated Effect</th>
            <th class="num">p-value</th>
            <th>Conclusion</th>
          </tr>
        </thead>
        <tbody>${rows.join('')}</tbody>
      </table>
      <p style="font-size:0.78rem;color:#888;margin-top:0.5rem">
        Conclusion fidelity: <strong>Correct Significant</strong> = same direction &amp; significant;
        <strong>Correct Direction</strong> = same direction but not significant;
        <strong>Null</strong> = near-zero effect;
        <strong>Wrong Direction/Significant</strong> = opposite to original.
      </p>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Distribution plots — all models overlaid
// ---------------------------------------------------------------------------
function renderAllModelDistributions(comparisons, conditionNames, xAxisLabel) {
  const hasAnyDist = comparisons.some(comp =>
    comp.distributions && Object.keys(comp.distributions).length > 0
  );
  if (!hasAnyDist) return '';

  const firstWithDist = comparisons.find(comp => comp.distributions && Object.keys(comp.distributions).length > 0);
  if (!firstWithDist) return '';
  const firstDist = firstWithDist.distributions[Object.keys(firstWithDist.distributions)[0]];
  if (!firstDist) return '';
  const origLabel = firstDist.original_type === 'empirical' ? 'Original (empirical)' : 'Original (Normal approx.)';

  const modelLegend = comparisons.map(comp => {
    const mc = getModelColor(comp.model);
    return `<span style="display:inline-flex;align-items:center;margin-right:1rem;font-size:0.82rem">
      <span style="display:inline-block;width:12px;height:12px;background:${mc.fill};border-radius:2px;margin-right:4px;opacity:0.7"></span>
      ${mc.label || comp.model}
    </span>`;
  }).join('');

  const plots = conditionNames
    .filter(cond => comparisons.some(comp => comp.distributions?.[cond]))
    .map(cond => renderMultiModelDistPlot(cond, comparisons, xAxisLabel))
    .join('');

  if (!plots) return '';

  return `
    <div style="margin-top:1.5rem">
      <h4 style="font-size:0.95rem;font-weight:600;margin-bottom:0.75rem">Distribution Comparison</h4>
      <div class="chart-legend">
        <span style="display:inline-flex;align-items:center;margin-right:1rem;font-size:0.82rem">
          <span style="display:inline-block;width:12px;height:12px;background:#dc2626;border-radius:2px;margin-right:4px;opacity:0.7"></span>
          ${origLabel}
        </span>
        ${modelLegend}
      </div>
      <div class="dist-grid">${plots}</div>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Distribution density plot (SVG) — multi-model overlay
// ---------------------------------------------------------------------------
/**
 * Choose nice round tick values covering [lo, hi].
 * For discrete data with few unique values (≤ 15), use the actual values.
 * Otherwise pick ~nTarget evenly spaced round numbers.
 */
function niceAxisTicks(lo, hi, binCenters, nTarget = 6) {
  // Check if data looks discrete (few unique non-zero-density bins)
  const unique = [...new Set(binCenters.map(v => +v.toFixed(6)))];
  if (unique.length <= 15) return unique;

  const range = hi - lo;
  if (range <= 0) return [lo];
  // Pick a "nice" step size
  const rawStep = range / nTarget;
  const mag = Math.pow(10, Math.floor(Math.log10(rawStep)));
  const candidates = [1, 2, 2.5, 5, 10];
  const niceStep = candidates.map(c => c * mag).find(s => range / s <= nTarget + 1) || rawStep;
  const ticks = [];
  const start = Math.ceil(lo / niceStep) * niceStep;
  for (let v = start; v <= hi + niceStep * 0.01; v += niceStep) {
    ticks.push(+v.toFixed(6));
  }
  return ticks;
}

function renderMultiModelDistPlot(condition, comparisons, xAxisLabel) {
  const W = 380, H = 210;
  const pad = {top: 10, right: 15, bottom: 50, left: 15};
  const plotW = W - pad.left - pad.right;
  const plotH = H - pad.top - pad.bottom;

  const modelDists = comparisons
    .filter(comp => comp.distributions?.[condition])
    .map(comp => ({ model: comp.model, dist: comp.distributions[condition] }));

  if (modelDists.length === 0) return '';

  const refDist = modelDists[0].dist;
  const centers = refDist.bin_centers;
  if (!centers || centers.length === 0) return '';

  // Support both density and counts formats — normalize to density
  function toDensity(arr, binWidth) {
    if (!arr || arr.length === 0) return centers.map(() => 0);
    const total = arr.reduce((s, v) => s + v, 0);
    if (total === 0) return arr;
    return arr.map(v => v / (total * binWidth));
  }

  const bw = refDist.bin_width || 1;
  const origDensity = refDist.original_density || toDensity(refDist.original_counts, bw);

  const xMin = centers[0] - bw / 2;
  const xMax = centers[centers.length - 1] + bw / 2;
  let yMax = Math.max(...origDensity);
  modelDists.forEach(md => {
    const repDensity = md.dist.replicated_density || toDensity(md.dist.replicated_counts, md.dist.bin_width || bw);
    yMax = Math.max(yMax, ...repDensity);
  });
  yMax *= 1.15;

  const xScale = (v) => pad.left + ((v - xMin) / (xMax - xMin)) * plotW;
  const yScaleGlobal = (v) => pad.top + plotH - (v / yMax) * plotH;
  const barW = (refDist.bin_width / (xMax - xMin)) * plotW;

  // Original distribution layer (red)
  const isEmpirical = refDist.original_type === 'empirical';
  let origLayer;
  if (isEmpirical) {
    origLayer = centers.map((c, i) => {
      const x = xScale(c) - barW / 2;
      const h = (origDensity[i] / yMax) * plotH;
      const y = pad.top + plotH - h;
      return `<rect x="${x.toFixed(1)}" y="${y.toFixed(1)}" width="${barW.toFixed(1)}" height="${h.toFixed(1)}" fill="#dc2626" opacity="0.3"/>`;
    }).join('');
  } else {
    const origPoints = centers.map((c, i) => `${xScale(c).toFixed(1)},${yScaleGlobal(origDensity[i]).toFixed(1)}`).join(' ');
    origLayer = `<polyline points="${origPoints}" fill="none" stroke="#dc2626" stroke-width="2.5"/>`;
  }

  // Replicated distribution layers — one curve per model
  const modelLayers = modelDists.map(md => {
    const mc = getModelColor(md.model);
    const repDensity = md.dist.replicated_density || toDensity(md.dist.replicated_counts, md.dist.bin_width || bw);
    const points = centers.map((c, i) =>
      `${xScale(c).toFixed(1)},${yScaleGlobal(repDensity[i]).toFixed(1)}`
    ).join(' ');
    const firstX = xScale(centers[0]).toFixed(1);
    const lastX = xScale(centers[centers.length - 1]).toFixed(1);
    const baseY = (pad.top + plotH).toFixed(1);
    const fillPoints = `${firstX},${baseY} ${points} ${lastX},${baseY}`;
    return `
      <polygon points="${fillPoints}" fill="${mc.fill}" opacity="${mc.fillAlpha * 0.6}"/>
      <polyline points="${points}" fill="none" stroke="${mc.stroke}" stroke-width="2" opacity="0.8"/>
    `;
  }).join('');

  // X-axis ticks — computed from actual data range
  const tickVals = niceAxisTicks(xMin, xMax, centers);
  const allIntegers = tickVals.every(v => Number.isInteger(v));
  const formatTick = (v) => allIntegers ? String(v) : (Number.isInteger(v) ? String(v) : v.toFixed(2).replace(/0+$/, '').replace(/\.$/, ''));

  let xTicksSvg = '';
  for (const val of tickVals) {
    const x = xScale(val);
    xTicksSvg += `<line x1="${x.toFixed(1)}" y1="${pad.top + plotH}" x2="${x.toFixed(1)}" y2="${pad.top + plotH + 4}" stroke="#999"/>`;
    xTicksSvg += `<text x="${x.toFixed(1)}" y="${pad.top + plotH + 16}" text-anchor="middle" font-size="10" fill="#666">${formatTick(val)}</text>`;
  }

  const baseLine = `<line x1="${pad.left}" y1="${pad.top + plotH}" x2="${pad.left + plotW}" y2="${pad.top + plotH}" stroke="#ccc"/>`;

  // Axis labels
  const xLabel = xAxisLabel
    ? `<text x="${pad.left + plotW / 2}" y="${H - 4}" text-anchor="middle" font-size="11" fill="#555">${xAxisLabel}</text>`
    : '';
  const yLabel = `<text x="${pad.left + 2}" y="${pad.top - 2}" text-anchor="start" font-size="10" fill="#888">Density</text>`;

  return `
    <div class="dist-plot">
      <div class="dist-plot-title">${formatCondition(condition)}</div>
      <svg width="${W}" height="${H}" style="display:block">
        ${baseLine}
        ${origLayer}
        ${modelLayers}
        ${xTicksSvg}
        ${xLabel}
        ${yLabel}
      </svg>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Reproduction package viewer
// ---------------------------------------------------------------------------
async function showReproduction(paperId, modality) {
  const detail = document.getElementById('paper-detail');
  const basePath = `static/data/reproduce/${paperId}_${modality}`;

  // Files to fetch
  const files = [
    { name: 'reproduce.py', lang: 'python' },
    { name: 'survey.json', lang: 'json' },
    { name: 'agents.json', lang: 'json' },
    { name: 'scenarios.json', lang: 'json' },
  ];

  const screenNote = modality === 'visual'
    ? ' In visual mode, the LLM sees screenshot images of the original decision screens instead of text descriptions.'
    : '';

  detail.innerHTML = `
    <span class="back-link" onclick="showPaperByDoi(allPapers.find(p=>p.id==='${paperId}')?.doi)">&larr; Back to paper</span>
    <div class="detail-header">
      <h2>Reproduction Package: ${paperId} (${modality})</h2>
      <div class="repro-instructions">
        <p>This package contains everything needed to replicate the ${modality}-mode simulation for this paper.${screenNote}</p>
        <p style="margin-top:0.4rem"><strong>How to run:</strong></p>
        <ol class="repro-steps">
          <li>Install the EDSL framework: <code>pip install edsl</code></li>
          <li>Download all files below into a single directory${modality === 'visual' ? ' (keep the <code>screens/</code> subfolder intact)' : ''}</li>
          <li>Run: <code>python reproduce.py</code></li>
          <li>Results will be saved to <code>results_${modality}.csv</code></li>
        </ol>
        <p style="margin-top:0.4rem"><strong>Files:</strong></p>
        <ul class="repro-file-desc">
          <li><code>reproduce.py</code> — Main script that loads the serialized objects and runs the simulation via EDSL</li>
          <li><code>survey.json</code> — The survey instrument (questions, answer options, instructions shown to the LLM)</li>
          <li><code>agents.json</code> — Simulated participant profiles with demographic traits matching the original sample</li>
          <li><code>scenarios.json</code> — Experimental conditions (treatments) presented to each agent${modality === 'visual' ? ', including references to the decision screen images' : ''}</li>
          ${modality === 'visual' ? '<li><code>screens/</code> — PNG screenshots of the original experiment decision screens shown to the LLM</li>' : ''}
        </ul>
      </div>
    </div>
    <div id="repro-files"><p style="color:#888">Loading files...</p></div>
  `;

  const container = document.getElementById('repro-files');
  const loaded = [];

  for (const file of files) {
    try {
      const res = await fetch(`${basePath}/${file.name}?${CACHE_BUST}`, { method: 'HEAD' });
      if (!res.ok) continue;
      loaded.push(file);
    } catch (e) {
      // skip missing files
    }
  }

  // Check for screen images in visual mode
  let screens = [];
  if (modality === 'visual') {
    try {
      // Try to read scenario file to discover screen filenames
      const scenRes = await fetch(`${basePath}/scenarios.json?${CACHE_BUST}`);
      if (scenRes.ok) {
        const scenData = await scenRes.json();
        const scenList = scenData.scenarios || scenData.data || [];
        const screenPaths = new Set();
        for (const s of scenList) {
          for (const [k, v] of Object.entries(s)) {
            if (typeof v === 'object' && v && v.path) {
              screenPaths.add(v.path);
            }
          }
        }
        screens = [...screenPaths].sort();
      }
    } catch (e) {
      // ignore
    }
  }

  if (loaded.length === 0) {
    container.innerHTML = '<p style="color:#dc2626">No reproduction files found.</p>';
    return;
  }

  let html = `<div class="repro-actions">
    <button class="repro-download-btn" onclick="downloadReproduction('${paperId}','${modality}')">Download all files</button>
  </div>`;

  for (const file of loaded) {
    html += `
      <div class="repro-file-row">
        <span class="repro-filename">${file.name}</span>
        <button class="repro-download-single-btn" onclick="downloadSingleFile('${basePath}/${file.name}','${file.name}')">Download</button>
      </div>
    `;
  }

  // Check for screen manifest (original vs generated comparison)
  let manifest = null;
  if (modality === 'visual') {
    try {
      const manRes = await fetch(`${basePath}/screen_manifest.json?${CACHE_BUST}`);
      if (manRes.ok) manifest = await manRes.json();
    } catch (e) { /* no manifest */ }
  }

  if (manifest && manifest.mappings && manifest.mappings.some(m => m.original_pages && m.original_pages.length > 0)) {
    // Side-by-side comparison view
    html += `
      <div class="repro-screens-header">
        <span class="repro-filename">Decision Screen Comparison (${manifest.mappings.length} screens)</span>
        <button class="repro-download-single-btn" onclick="downloadAllScreens('${basePath}', ${JSON.stringify(screens)})">Download generated screens</button>
      </div>
      <p class="repro-comparison-note">Original screenshots are full PDF appendix pages from the paper. Generated screens are per-task images shown to the LLM during simulation.</p>
      <div class="repro-comparison-grid">
        ${manifest.mappings.map(m => {
          const origSrc = m.original_pages && m.original_pages[0]
            ? `${basePath}/original_screens/${m.original_pages[0]}`
            : null;
          const genSrc = `${basePath}/screens/${m.generated}`;
          return `<div class="repro-comparison-pair">
            <div class="repro-comparison-item">
              <div class="repro-comparison-label">Original (paper appendix)</div>
              ${origSrc
                ? `<img src="${origSrc}?${CACHE_BUST}" alt="Original">`
                : '<div class="repro-no-original">No original available</div>'}
            </div>
            <div class="repro-comparison-item">
              <div class="repro-comparison-label">Generated (shown to LLM)</div>
              <img src="${genSrc}?${CACHE_BUST}" alt="Generated">
            </div>
            <div class="repro-comparison-caption">${m.task_label || m.generated}</div>
          </div>`;
        }).join('')}
      </div>
    `;
  } else if (screens.length > 0) {
    // Generated-only grid (no originals available)
    html += `
      <div class="repro-screens-header">
        <span class="repro-filename">screens/ (${screens.length} decision screen images)</span>
        <button class="repro-download-single-btn" onclick="downloadAllScreens('${basePath}', ${JSON.stringify(screens)})">Download all screens</button>
      </div>
      <div class="repro-screens-grid">
        ${screens.map(s => {
          const fname = s.split('/').pop();
          return `<div class="repro-screen-item">
            <img src="${basePath}/${s}?${CACHE_BUST}" alt="${fname}">
            <div class="repro-screen-label">${fname}</div>
            <button class="repro-download-single-btn" onclick="downloadSingleFile('${basePath}/${s}','${fname}')">Download</button>
          </div>`;
        }).join('')}
      </div>
    `;
  }

  container.innerHTML = html;
}

function downloadSingleFile(url, filename) {
  const a = document.createElement('a');
  a.href = `${url}?${CACHE_BUST}`;
  a.download = filename;
  a.click();
}

async function downloadAllScreens(basePath, screenPaths) {
  for (const s of screenPaths) {
    const fname = s.split('/').pop();
    downloadSingleFile(`${basePath}/${s}`, fname);
    await new Promise(r => setTimeout(r, 200));
  }
}

async function downloadReproduction(paperId, modality) {
  const basePath = `static/data/reproduce/${paperId}_${modality}`;
  const fileNames = ['reproduce.py', 'survey.json', 'agents.json', 'scenarios.json'];

  // Collect all file contents
  const files = [];
  for (const name of fileNames) {
    try {
      const res = await fetch(`${basePath}/${name}?${CACHE_BUST}`);
      if (res.ok) {
        const blob = await res.blob();
        files.push({ name, blob });
      }
    } catch (e) { /* skip */ }
  }

  if (files.length === 0) return;

  // If only one file, download directly; otherwise create a simple concatenated download
  // For a proper zip we'd need a library, so we download files individually
  for (const file of files) {
    const url = URL.createObjectURL(file.blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = file.name;
    a.click();
    URL.revokeObjectURL(url);
    // Small delay between downloads so browser doesn't block them
    await new Promise(r => setTimeout(r, 200));
  }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function formatCondition(name) {
  return String(name)
    .replace(/_/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());
}

function fmtNum(val) {
  const n = parseFloat(val);
  if (isNaN(n)) return val;
  return n.toFixed(4);
}
